```plantuml
@startuml
namespace persistence {
  namespace server {
    namespace entity {
      class Server as C {
        <<C>>
        seq : Integer
        name : String
        ip : String
      }
    }
  }

  namespace author {
    namespace entity {
      class Author as C {
        <<C>>
        seq : Integer
        name : String
        regDate : Date
      }
    }
  }

  namespace member {
    namespace entity {
      class Member as C {
        <<C>>
        seq : Integer
        id : String
        password : String
        name : String
        type : MemberType
      }
      enum MemberType as E {
        <<E>>
        USER, ADMIN
      }
    }
  }

  namespace book {
    namespace entity {
      class Book as A {
        <<A>>
        seq : Integer
        title : String
        author : Author
        regDate : Date
        expireDate : Date
        register : Member
        descriptionUrl : String
        tags : List<Tag>
      }
      class ScanBook as C {
        <<C>>
        fileName : String
        fileHash : String
        path : String
        server : Server
        size : Integer
      }
      class RidiBook as C {
        <<C>>
        url : String
        ridiUserId : String
      }
      class Tag as C {
        <<C>>
        seq : Integer
        value : String
      }
      Book <|-- ScanBook
      Book <|-- RidiBook
    }
  }
}
@enduml
